from typing import List

class Solution:
  def solve(self, nums: List[int]) -> bool:
    n = len(nums)
    for i in range(n):
      for j in range(i + 1, n):
        if nums[i] == nums[j] and (i + 1 == j or nums[i + 1] == nums[j + 1]):
          return True
    return False

# Read input from sys.stdin
with open("input.txt", "r") as f:
  n, *nums = map(int, f.readline().split())

# Output to sys.stdout
with open("output.txt", "w") as f:
  f.write("{\n  " + ("true" if Solution().solve(nums) else "false") + "\n}")

