#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
  bool solve(vector<int>& nums) {
    int n = nums.size();
    for (int i = 0; i < n; i++) {
      for (int j = i + 1; j < n; j++) {
        if (nums[i] == nums[j] && (i + 1 == j || nums[i + 1] == nums[j + 1])) {
          return true;
        }
      }
    }
    return false;
  }
};

int main() {
  cin >> n;
  cin >> nums[0];
  for (int i = 1; i < n; i++) {
    cin >> nums[i];
  }
  cout << (Solution().solve(nums) ? "true" : "false") << "\n";
  return 0;
}
